24	static void FilterAnsiColor(std::string& __format__) {
25	#ifdef ANSI_HIGH_LIGHT
26	    if (!Logger::IsLight()) {
27	        std::size_t pos = __format__.find("\033[3");
28	        if (pos != std::string::npos) {
29	            do {
30	                __format__.erase(pos, 5);
31	                pos = __format__.find("\033[3");
32	            } while (pos != std::string::npos);
33	        }
34	
35	        pos = __format__.find("\033[9");
36	        if (pos != std::string::npos) {
37	            do {
38	                __format__.erase(pos, 5);
39	                pos = __format__.find("\033[9");
40	            } while (pos != std::string::npos);
41	        }
42	
43	        pos = __format__.find("\x1b[0m");
44	        if (pos != std::string::npos) {
45	            do {
46	                __format__.erase(pos, 4);
47	                pos = __format__.find("\x1b[0m");
48	            } while (pos != std::string::npos);
49	        }
50	    }
51	#endif
52	}
