54	void Logger::debug(uint32_t __lv, const char *__restrict __format, ...) {
55	    if (Logger::GetDebugLevel() >= __lv) {
56	        std::string buffer;
57	        buffer.append(Logger::LightGreen());
58	        buffer.append(__format);
59	        buffer.append(Logger::End());
60	        FilterAnsiColor(buffer);
61	        va_list ap;
62	        va_start(ap, __format);
63	        vfprintf(stdout, buffer.c_str(), ap);
64	        va_end(ap);
65	    }
66	}
