23	std::string Utils::ConvertAscii(uint64_t value, int len) {
24	    std::string sb;
25	    uint8_t byte;
26	    for (int i = 0; i < len; i++) {
27	        byte = (value >> (8 * i)) & 0xFF;
28	        if (byte > 0x20 && byte < 0x7F) {
29	            sb += byte;
30	        } else {
31	            sb.append(".");
32	        }
33	    }
34	    return sb;
35	}
36	
37	uint64_t Utils::atol(const char* src) {
38	    uint64_t value;
39	    sscanf(src, "%" PRIx64 "", &value);
40	    return value;
41	}
