51	uint32_t Utils::CRC32(uint8_t* data, uint32_t len) {
52	    uint32_t crc = 0xFFFFFFFF;
53	    for (uint32_t k = 0; k < len; ++k) {
54	        crc ^= (uint32_t)data[k] << 24;
55	        for (int i = 0; i < 8; ++i) {
56	            if (crc & (1 << 31)) {
57	                crc = (crc << 1) ^ 0x04C11DB7;
58	            } else {
59	                crc <<= 1;
60	            }
61	            crc &= 0xFFFFFFFF;
62	        }
63	    }
64	    return crc;
65	}
66	
67	uint64_t Utils::CRC64(uint8_t* data, uint64_t len) {
68	    uint64_t crc = 0xFFFFFFFFFFFFFFFF;
69	    for (uint64_t k = 0; k < len; ++k) {
70	        crc ^= (uint64_t)data[k] << 56;
71	        for (int i = 0; i < 8; ++i) {
72	            if (crc & (1ULL << 63)) {
73	                crc = (crc << 1) ^ 0x42F0E1EBA9EA3693;
74	            } else {
75	                crc <<= 1;
76	            }
77	        }
78	    }
79	    return crc;
80	}
