30	MemoryMap* MemoryMap::MmapFile(const char* file, uint64_t off) {
31	    struct stat sb;
32	    if (stat(file, &sb) == -1)
33	        return nullptr;
34	
35	    if (off >= sb.st_size)
36	        return nullptr;
37	
38	    return MmapFile(file, sb.st_size - off, off);
39	}
40	
41	MemoryMap* MemoryMap::MmapFile(const char* file, uint64_t size, uint64_t off) {
42	    int fd = open(file, O_RDONLY);
43	    if (fd == -1)
44	        return nullptr;
45	
46	    MemoryMap *map = MmapFile(fd, size, off);
47	    close(fd);
48	    if (map) map->setFile(file, off);
49	    return map;
50	}
51	
52	MemoryMap* MemoryMap::MmapFile(int fd, uint64_t size, uint64_t off) {
53	    MemoryMap *map = nullptr;
54	    struct stat sb;
55	    if (fd > 0) {
56	        if (fstat(fd, &sb) == -1)
57	            return nullptr;
58	
59	        if (off >= sb.st_size)
60	            return nullptr;
61	
62	        void* mem = mmap(NULL, size, PROT_READ, MAP_PRIVATE, fd, off);
63	        if (mem != MAP_FAILED) {
64	            uint64_t real_size = std::min(size, sb.st_size - off);
65	            map = new MemoryMap(mem, size, off, real_size);
66	        }
67	    }
68	    return map;
69	}
