75	MemoryMap* MemoryMap::MmapMem(uint64_t addr, uint64_t size, uint64_t realSize) {
76	    MemoryMap *map = nullptr;
77	    void* mem = mmap(NULL, size, PROT_READ | PROT_WRITE, MAP_PRIVATE | MAP_ANON, -1, 0);
78	    if (mem != MAP_FAILED) {
79	        map = new MemoryMap(mem, size, 0, size);
80	        memcpy(mem, reinterpret_cast<void *>(addr), realSize);
81	    }
82	    return map;
83	}
84	
85	MemoryMap* MemoryMap::MmapZeroMem(uint64_t size) {
86	    MemoryMap *map = nullptr;
87	    void* mem = mmap(NULL, size, PROT_READ | PROT_WRITE, MAP_PRIVATE | MAP_ANON, -1, 0);
88	    if (mem != MAP_FAILED) {
89	        map = new MemoryMap(mem, size, 0, size);
90	        memset(mem, 0x0, size);
91	    }
92	    return map;
93	}
