27	MemoryMap* MemoryMap::MmapFile(const char* file, uint64_t off) {
28	    HANDLE hFile = CreateFileA(file, GENERIC_READ, FILE_SHARE_READ,
29	                               NULL, OPEN_EXISTING, FILE_ATTRIBUTE_NORMAL, NULL);
30	    if (hFile == INVALID_HANDLE_VALUE)
31	        return nullptr;
32	
33	    LARGE_INTEGER fileSize;
34	    if (!GetFileSizeEx(hFile, &fileSize)) {
35	        CloseHandle(hFile);
36	        return nullptr;
37	    }
38	
39	    CloseHandle(hFile);
40	
41	    if (off >= (uint64_t)fileSize.QuadPart)
42	        return nullptr;
43	
44	    return MmapFile(file, fileSize.QuadPart - off, off);
45	}
46	
47	MemoryMap* MemoryMap::MmapFile(const char* file, uint64_t size, uint64_t off) {
48	    HANDLE hFile = CreateFileA(file, GENERIC_READ, FILE_SHARE_READ,
49	                               NULL, OPEN_EXISTING, FILE_ATTRIBUTE_NORMAL, NULL);
50	    if (hFile == INVALID_HANDLE_VALUE)
51	        return nullptr;
52	
53	    LARGE_INTEGER fileSize;
54	    if (!GetFileSizeEx(hFile, &fileSize)) {
55	        CloseHandle(hFile);
56	        return nullptr;
57	    }
58	
59	    if (off >= (uint64_t)fileSize.QuadPart) {
60	        CloseHandle(hFile);
61	        return nullptr;
62	    }
63	
64	    HANDLE hMap = CreateFileMappingA(hFile, NULL, PAGE_READONLY, 0, 0, NULL);
65	    if (!hMap) {
66	        CloseHandle(hFile);
67	        return nullptr;
68	    }
69	
70	    void* mem = MapViewOfFile(hMap, FILE_MAP_READ,
71	                              (DWORD)(off >> 32), (DWORD)(off & 0xFFFFFFFF), size);
72	    CloseHandle(hMap);
73	    CloseHandle(hFile);
74	
75	    if (!mem)
76	        return nullptr;
77	
78	    uint64_t real_size = size;
79	    if (off + size > (uint64_t)fileSize.QuadPart)
80	        real_size = fileSize.QuadPart - off;
81	
82	    MemoryMap* map = new MemoryMap(mem, size, off, real_size);
83	    map->setFile(file, off);
84	    return map;
85	}
