91	MemoryMap* MemoryMap::MmapMem(uint64_t addr, uint64_t size, uint64_t realSize) {
92	    void* mem = VirtualAlloc(NULL, size, MEM_COMMIT | MEM_RESERVE, PAGE_READWRITE);
93	    if (!mem)
94	        return nullptr;
95	
96	    MemoryMap* map = new MemoryMap(mem, size, 0, size);
97	    memcpy(mem, reinterpret_cast<void*>(addr), realSize);
98	    return map;
99	}
100	
101	MemoryMap* MemoryMap::MmapZeroMem(uint64_t size) {
102	    void* mem = VirtualAlloc(NULL, size, MEM_COMMIT | MEM_RESERVE, PAGE_READWRITE);
103	    if (!mem)
104	        return nullptr;
105	
106	    MemoryMap* map = new MemoryMap(mem, size, 0, size);
107	    memset(mem, 0x0, size);
108	    return map;
109	}
