122	    if (mBegin) {
123	        // Try UnmapViewOfFile first (for file mappings), fall back to VirtualFree
124	        if (!UnmapViewOfFile(mBegin))
125	            VirtualFree(mBegin, 0, MEM_RELEASE);
126	    }
